   145	func Attempt(ctx context.Context, store Store, beadID string, opts AttemptOpts) (Outcome, error) {
   146		if opts.Executor == nil {
   147			return Outcome{}, fmt.Errorf("try attempt: executor is required")
   148		}
   149		rateCfg := resolveRateLimitRetryConfig(opts)
   150		var (
   151			report Report
   152			err    error
   153		)
   154		for retryCount, elapsed := 0, time.Duration(0); ; {
   155			report, err = opts.Executor.Execute(ctx, beadID)
   156			if err != nil {
   157				report = Report{
   158					BeadID: beadID,
   159					Status: StatusExecutionFailed,
   160					Detail: err.Error(),
   161					Error:  err.Error(),
   162				}
   163			}
   164			if report.BeadID == "" {
   165				report.BeadID = beadID
   166			}
   167			if report.Status == "" {
   168				report.Status = StatusExecutionFailed
   169			}
   170	
   171			rateLimited := IsRateLimitReport(&report)
   172			effectiveBudget := rateCfg.Budget
   173			if opts.RateLimitBudget == 0 && report.RateLimitBudget != 0 {
   174				effectiveBudget = report.RateLimitBudget
   175			}
   176			decision, retryAfter := evaluateRateLimitAttempt(report, rateCfg, retryCount+1, elapsed, effectiveBudget)
   177			if !decision.ShouldRetry {
   178				if decision.Reason != "" {
   179					report.Error = decision.Reason
   180				}
   181				if rateLimited && decision.Reason != "" && rateCfg.OnRetry != nil {
   182					rateCfg.OnRetry(ctx, RateLimitRetryInfo{
   183						Attempt:    retryCount + 1,
   184						Source:     decision.Source,
   185						Report:     &report,
   186						Elapsed:    elapsed,
   187						RetryAfter: retryAfter,
   188						OverBudget: true,
   189					})
   190				}
   191				break
   192			}
   193	
   194			retryCount++
   195			info := RateLimitRetryInfo{
   196				Attempt:    retryCount,
   197				Wait:       decision.Wait,
   198				Source:     decision.Source,
   199				Report:     &report,
   200				Elapsed:    elapsed,
   201				RetryAfter: retryAfter,
   202			}
   203			if rateCfg.OnRetry != nil {
   204				rateCfg.OnRetry(ctx, info)
   205			}
   206			if err := rateCfg.Sleep(ctx, decision.Wait); err != nil {
   207				return Outcome{}, err
   208			}
   209			elapsed += decision.Wait
   210		}
   211	
   212		if ShouldAttemptConflictRecovery(report, opts.ProjectRoot) {
   213			if opts.Store == nil {
   214				opts.Store = store
   215			}
   216			return ConflictRecoveryOutcome(ctx, ConflictRecoveryInput{
   217				Bead:             opts.Bead,
   218				Report:           report,
   219				ProjectRoot:      opts.ProjectRoot,
   220				AutoRecover:      opts.AutoRecover,

