   353	type RateLimitRetryConfig struct {
   354		Budget     time.Duration
   355		PerWaitCap time.Duration
   356		Sleep      func(ctx context.Context, d time.Duration) error
   357		Now        func() time.Time
   358		Evaluator  func(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision
   359		OnRetry    func(ctx context.Context, info RateLimitRetryInfo)
   360	}
   361	
   362	const (
   363		RateLimitRetryDefaultBudget     = 5 * time.Minute
   364		RateLimitRetryDefaultPerWaitCap = 60 * time.Second
   365		RateLimitBudgetExhaustedReason  = "rate-limited beyond budget"
   366	)
   367	
   368	var rateLimitBackoffSchedule = []time.Duration{
   369		1 * time.Second,
   370		5 * time.Second,
   371		15 * time.Second,
   372		30 * time.Second,
   373		60 * time.Second,
   374	}
   375	
   376	type RateLimitWaitDecision struct {
   377		ShouldRetry bool
   378		Wait        time.Duration
   379		Source      string
   380		Reason      string
   381	}
   382	
   383	type RateLimitRetryInfo struct {
   384		Attempt    int
   385		Wait       time.Duration
   386		Source     string
   387		Report     *Report
   388		Elapsed    time.Duration
   389		RetryAfter time.Duration
   390		OverBudget bool
   391	}
   392	
   393	func resolveRateLimitRetryConfig(opts AttemptOpts) RateLimitRetryConfig {
   394		cfg := RateLimitRetryConfig{
   395			Budget:     opts.RateLimitBudget,
   396			PerWaitCap: opts.RateLimitPerWaitCap,
   397			Evaluator:  opts.RateLimitWaitEvaluator,
   398			Sleep:      opts.RateLimitSleep,
   399			Now:        opts.RateLimitNow,
   400			OnRetry:    opts.RateLimitOnRetry,
   401		}
   402		if cfg.Budget == 0 {
   403			cfg.Budget = RateLimitRetryDefaultBudget
   404		}
   405		if cfg.PerWaitCap == 0 {
   406			cfg.PerWaitCap = RateLimitRetryDefaultPerWaitCap
   407		}
   408		if cfg.Sleep == nil {
   409			cfg.Sleep = ctxSleep
   410		}
   411		if cfg.Now == nil {
   412			cfg.Now = time.Now
   413		}
   414		if cfg.Evaluator == nil {
   415			cfg.Evaluator = EvaluateRateLimitWait
   416		}
   417		return cfg
   418	}
   419	
   420	func ctxSleep(ctx context.Context, d time.Duration) error {
   421		if d <= 0 {
   422			return nil
   423		}
   424		t := time.NewTimer(d)
   425		defer t.Stop()
   426		select {
   427		case <-ctx.Done():
   428			return ctx.Err()
   429		case <-t.C:
   430			return nil
   431		}
   432	}
   433	
   434	func evaluateRateLimitAttempt(report Report, cfg RateLimitRetryConfig, attempt int, elapsed, budget time.Duration) (RateLimitWaitDecision, time.Duration) {
   435		if cfg.Budget < 0 || budget < 0 {
   436			return RateLimitWaitDecision{ShouldRetry: false}, 0
   437		}
   438		if !IsRateLimitReport(&report) {
   439			return RateLimitWaitDecision{ShouldRetry: false}, 0
   440		}
   441	
   442		retryAfter := ExtractRetryAfterFromStderr(report.Stderr, cfg.Now())
   443		decision := cfg.Evaluator(retryAfter, attempt, elapsed, budget, cfg.PerWaitCap)
   444		if !decision.ShouldRetry {
   445			decision.Reason = RateLimitBudgetExhaustedReason
   446		}
   447		return decision, retryAfter
   448	}
   449	
   450	func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
   451		if budget > 0 && elapsed >= budget {
   452			return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
   453		}
   454	
   455		var wait time.Duration
   456		var source string
   457		if retryAfter > 0 {
   458			wait = retryAfter
   459			source = "retry-after"
   460		} else {
   461			idx := attempt - 1
   462			if idx < 0 {
   463				idx = 0
   464			}
   465			if idx >= len(rateLimitBackoffSchedule) {
   466				idx = len(rateLimitBackoffSchedule) - 1
   467			}
   468			wait = rateLimitBackoffSchedule[idx]
   469			source = "exponential-backoff"
   470		}

